  firebase.initializeApp(firebaseConfig);
  const auth = firebase.auth();
  const db = firebase.firestore();

  let currentUserData = null;

  function register(){
    const email = regEmail.value;
    const pass = regPassword.value;
    auth.createUserWithEmailAndPassword(email,pass)
    .then(user=>{
      db.collection("users").doc(user.user.uid).set({
        email:email,
        balance:0,
        role:"user",
        createdAt:new Date()
      });
      alert("Registered!");
    });
  }

  function login(){
    auth.signInWithEmailAndPassword(loginEmail.value,loginPassword.value);
  }

  function logout(){
    auth.signOut();
  }

  auth.onAuthStateChanged(user=>{
    if(user){
      authSection.classList.add("hidden");
      dashboardSection.classList.remove("hidden");
      loadUser(user.uid);
      loadServices();
      loadOrders(user.uid);
    } else {
      authSection.classList.remove("hidden");
      dashboardSection.classList.add("hidden");
    }
  });

  function loadUser(uid){
    db.collection("users").doc(uid).onSnapshot(doc=>{
      currentUserData = doc.data();
      userBalance.innerText = currentUserData.balance;
    });
  }

  function loadServices(){
    db.collection("services").get().then(snapshot=>{
      serviceSelect.innerHTML="";
      snapshot.forEach(doc=>{
        let s=doc.data();
        serviceSelect.innerHTML+=`
          ${s.name} - $${s.price}
        `;
      });
    });
  }

  function placeOrder(){
    let serviceId=serviceSelect.value;
    let price=parseFloat(serviceSelect.selectedOptions[0].dataset.price);
    let qty=parseInt(orderQty.value);
    let total=price*qty;

    if(currentUserData.balance{
      ordersList.innerHTML="";
      snapshot.forEach(doc=>{
        let o=doc.data();
        ordersList.innerHTML+=`



ID: ${doc.id}

Service: ${o.serviceId}

Status: ${o.status}
          `;
      });
    });
  }

  function submitPayment(){
    db.collection("payments").add({
      userId:auth.currentUser.uid,
      network:network.value,
      amount:parseFloat(amount.value),
      transactionId:txId.value,
      phone:phone.value,
      status:"Pending",
      createdAt:new Date()
    });
    alert("Payment Submitted");
  }

  function showPage(page){
    homePage.classList.add("hidden");
    orderPage.classList.add("hidden");
    ordersPage.classList.add("hidden");
    fundsPage.classList.add("hidden");

    if(page=="home")homePage.classList.remove("hidden");
    if(page=="order")orderPage.classList.remove("hidden");
    if(page=="orders")ordersPage.classList.remove("hidden");
    if(page=="funds")fundsPage.classList.remove("hidden");
  }
